@Override
public IBallCmd interactWith(IBall source, IBall target, IDispatcher<IBallCmd> disp) {
	// Return a command that applies collision physics
	return (context, d) -> {
		Point sourceLoc = source.getLocation();
		Point targetLoc = target.getLocation();

		// Calculate distance between centers
		double dx = targetLoc.x - sourceLoc.x;
		double dy = targetLoc.y - sourceLoc.y;
		double distance = Math.sqrt(dx * dx + dy * dy);

		double minSeparation = source.getRadius() + target.getRadius();

		// Only collide if overlapping
		if (distance < minSeparation) {
			// Calculate unit vector from source to target
			Point2D.Double unitVec = calcUnitVec(sourceLoc, targetLoc, distance);

			// Calculate masses (proportional to radius squared)
			double sourceMass = source.getRadius() * source.getRadius();
			double targetMass = target.getRadius() * target.getRadius();

			// Calculate reduced mass
			double reducedMass = reducedMass(sourceMass, targetMass);

			// Calculate impulse
			Point2D.Double impulseVec = impulse(unitVec, source.getVelocity(), target.getVelocity(), reducedMass);

			// Update velocities
			updateVelocity(source, sourceMass, impulseVec);
			updateVelocity(target, targetMass, new Point2D.Double(-impulseVec.x, -impulseVec.y));

			// Nudge balls apart to prevent sticking
			Point nudgeVec = calcNudgeVec(unitVec, minSeparation, distance);
			source.setLocation(new Point(sourceLoc.x - nudgeVec.x / 2, sourceLoc.y - nudgeVec.y / 2));
			target.setLocation(new Point(targetLoc.x + nudgeVec.x / 2, targetLoc.y + nudgeVec.y / 2));
		}
	};
}

