@Override
public void updateState(final IBall source, IDispatcher<IBallCmd> dispatcher) {
	// For each other ball in the dispatcher
	for (Object observer : dispatcher.getAllObservers()) {
		IBall otherBall = (IBall) observer;

		// Skip self
		if (otherBall == source) {
			continue;
		}

		// Calculate distance between centers
		Point sourceLoc = source.getLocation();
		Point otherLoc = otherBall.getLocation();
		double dx = otherLoc.x - sourceLoc.x;
		double dy = otherLoc.y - sourceLoc.y;
		double distance = Math.sqrt(dx * dx + dy * dy);

		// Check if balls overlap (distance < sum of radii)
		double minSeparation = source.getRadius() + otherBall.getRadius();
		if (distance < minSeparation) {
			// Trigger interaction
			IBallCmd cmd = source.interactWithThen(otherBall, dispatcher);
			dispatcher.updateAll(cmd);
		}
	}
}

